/**
 * CASL Permission Middleware
 *
 * Handles authorization and permission checking using CASL.
 * Implements RBAC (Role-Based) and ABAC (Attribute-Based) access control
 * as defined in SECURITY_MODEL.md.
 *
 * @module core/middleware/permission
 */

import { Request, Response, NextFunction, RequestHandler } from 'express';
import {
  AbilityBuilder,
  PureAbility,
  AbilityClass,
  InferSubjects,
  ExtractSubjectType,
  MongoAbility,
  createMongoAbility,
} from '@casl/ability';
import { AppException } from '@/core/exceptions/app.exception';
import { AuthenticatedRequest, AuthUser } from '@/core/middleware/auth.middleware';
import { TenantRequest, TenantOrganization } from '@/core/middleware/tenant.middleware';

// -----------------------------------------------------------------------------
// Type Definitions
// -----------------------------------------------------------------------------

/**
 * Available actions for permission checks
 * Follows CRUD + custom action patterns
 */
export type PermissionAction =
  | 'manage'    // Full control (create, read, update, delete)
  | 'create'
  | 'read'
  | 'update'
  | 'delete'
  | 'publish'   // Publish/unpublish resources
  | 'view'      // Same as read, but for UI distinction
  | 'export'    // Export data
  | 'import'    // Import data
  | 'use'       // Use a feature (e.g., AI)
  | 'access';   // Access a resource/feature

/**
 * Subject types for CASL ability definitions
 * Maps to resource types in the system
 */
export type PermissionSubject =
  | 'all'
  | 'Organization'
  | 'Branch'
  | 'User'
  | 'Role'
  | 'Menu'
  | 'Category'
  | 'Product'
  | 'Order'
  | 'Table'
  | 'QRCode'
  | 'Media'
  | 'Notification'
  | 'Subscription'
  | 'Analytics'
  | 'AI'
  | 'Module'
  | 'Settings'
  | 'AuditLog';

/**
 * CASL Ability type for this application
 */
export type AppAbility = MongoAbility<[PermissionAction, PermissionSubject]>;

/**
 * Extended request with CASL ability
 */
export interface PermissionRequest extends TenantRequest {
  /** CASL ability for permission checks */
  ability: AppAbility;
}

/**
 * Optional permission request (for routes where auth is optional)
 */
export interface OptionalPermissionRequest extends AuthenticatedRequest {
  /** CASL ability for permission checks (optional) */
  ability?: AppAbility;
  /** Organization context (optional) */
  organization?: TenantOrganization;
}

/**
 * Plan tier type for plan-based restrictions
 */
export type PlanTier = 'free' | 'starter' | 'professional' | 'business' | 'enterprise';

/**
 * Plan tier hierarchy (index = level, higher = more permissions)
 */
const PLAN_HIERARCHY: PlanTier[] = ['free', 'starter', 'professional', 'business', 'enterprise'];

/**
 * Gets the numeric level of a plan tier
 */
function getPlanLevel(tier: PlanTier | string | null | undefined): number {
  if (!tier) return 0;
  const index = PLAN_HIERARCHY.indexOf(tier as PlanTier);
  return index >= 0 ? index : 0;
}

// -----------------------------------------------------------------------------
// CASL Ability Builder
// -----------------------------------------------------------------------------

/**
 * Defines CASL abilities for a user based on their role and organization.
 * Implements the ability builder pattern from SECURITY_MODEL.md section 3.4.
 *
 * @param user - Authenticated user context
 * @param organization - Organization/tenant context (optional for platform users)
 * @param planTier - Organization's subscription plan tier
 * @returns CASL ability instance
 *
 * @example
 * ```typescript
 * const ability = defineAbilitiesFor(user, organization, 'professional');
 * if (ability.can('create', 'Menu')) {
 *   // User can create menus
 * }
 * ```
 */
export function defineAbilitiesFor(
  user: AuthUser,
  organization?: TenantOrganization,
  planTier?: PlanTier | string | null
): AppAbility {
  const { can, cannot, build } = new AbilityBuilder<AppAbility>(createMongoAbility);

  // -------------------------------------------------------------------------
  // Platform Admin Roles (System-wide access)
  // -------------------------------------------------------------------------

  const platformRoles = ['super_admin', 'admin', 'sales', 'support'];
  const isPlatformAdmin = platformRoles.includes(user.role);

  if (user.role === 'super_admin') {
    // Super admin has full access to everything
    can('manage', 'all');
    return build();
  }

  if (user.role === 'admin') {
    // Admin can manage most platform resources
    can('manage', 'Organization');
    can('manage', 'User');
    can('manage', 'Subscription');
    can('view', 'AuditLog');
    can('manage', 'Module');
    can('manage', 'Settings');
    return build();
  }

  if (user.role === 'sales') {
    // Sales can view organizations and manage CRM
    can('view', 'Organization');
    can('create', 'Organization');
    can('view', 'User');
    can('view', 'Subscription');
    return build();
  }

  if (user.role === 'support') {
    // Support can view and help with issues
    can('view', 'Organization');
    can('view', 'User');
    can('view', 'Order');
    can('view', 'Menu');
    return build();
  }

  // -------------------------------------------------------------------------
  // Organization Roles (Tenant-scoped access)
  // -------------------------------------------------------------------------

  // For non-platform roles, organization context is required
  if (!organization) {
    // No permissions without organization context
    return build();
  }

  const orgId = organization.id;

  // Base tenant isolation - CRITICAL: Always scope to organization
  // All following rules implicitly apply this condition
  const orgCondition = { organizationId: orgId };

  switch (user.role) {
    case 'owner':
      // Owner has full access within their organization
      can('manage', 'Organization', { id: orgId });
      can('manage', 'Branch', orgCondition);
      can('manage', 'User', orgCondition);
      can('manage', 'Role', orgCondition);
      can('manage', 'Menu', orgCondition);
      can('manage', 'Category', orgCondition);
      can('manage', 'Product', orgCondition);
      can('manage', 'Order', orgCondition);
      can('manage', 'Table', orgCondition);
      can('manage', 'QRCode', orgCondition);
      can('manage', 'Media', orgCondition);
      can('manage', 'Notification', orgCondition);
      can('manage', 'Subscription', orgCondition);
      can('view', 'Analytics', orgCondition);
      can('export', 'Analytics', orgCondition);
      can('use', 'AI', orgCondition);
      can('manage', 'Settings', orgCondition);
      can('view', 'AuditLog', orgCondition);
      break;

    case 'manager':
      // Manager can manage most resources except billing
      can('read', 'Organization', { id: orgId });
      can('manage', 'Branch', orgCondition);
      can('manage', 'User', { ...orgCondition, role: { $ne: 'owner' } });
      can('manage', 'Menu', orgCondition);
      can('manage', 'Category', orgCondition);
      can('manage', 'Product', orgCondition);
      can('manage', 'Order', orgCondition);
      can('manage', 'Table', orgCondition);
      can('manage', 'QRCode', orgCondition);
      can('manage', 'Media', orgCondition);
      can('read', 'Notification', orgCondition);
      can('view', 'Analytics', orgCondition);
      can('export', 'Analytics', orgCondition);
      can('view', 'Settings', orgCondition);
      // Managers cannot manage billing/subscription
      cannot('manage', 'Subscription');
      break;

    case 'staff':
      // Staff can manage orders and update menus
      can('read', 'Organization', { id: orgId });
      can('read', 'Menu', orgCondition);
      can('update', 'Menu', orgCondition);
      can('read', 'Category', orgCondition);
      can('update', 'Category', orgCondition);
      can('read', 'Product', orgCondition);
      can('update', 'Product', orgCondition);
      can('manage', 'Order', orgCondition);
      can('manage', 'Table', orgCondition);
      can('read', 'QRCode', orgCondition);
      can('create', 'Media', orgCondition);
      can('read', 'Media', orgCondition);
      can('read', 'Notification', orgCondition);
      // Staff cannot delete menus/products or manage users
      cannot('delete', 'Menu');
      cannot('delete', 'Category');
      cannot('delete', 'Product');
      cannot('manage', 'User');
      break;

    case 'cashier':
      // Cashier can handle orders and tables
      can('read', 'Organization', { id: orgId });
      can('read', 'Menu', orgCondition);
      can('read', 'Category', orgCondition);
      can('read', 'Product', orgCondition);
      can('create', 'Order', orgCondition);
      can('read', 'Order', orgCondition);
      can('update', 'Order', orgCondition);
      can('read', 'Table', orgCondition);
      can('update', 'Table', orgCondition);
      can('read', 'QRCode', orgCondition);
      // Cashier cannot modify menu items or cancel orders
      cannot('delete', 'Order');
      break;

    case 'viewer':
      // Viewer has read-only access
      can('read', 'Organization', { id: orgId });
      can('read', 'Menu', orgCondition);
      can('read', 'Category', orgCondition);
      can('read', 'Product', orgCondition);
      can('read', 'Order', orgCondition);
      can('read', 'Table', orgCondition);
      can('read', 'QRCode', orgCondition);
      can('view', 'Analytics', orgCondition);
      break;

    default:
      // Unknown role - minimal permissions
      can('read', 'Organization', { id: orgId });
      break;
  }

  // -------------------------------------------------------------------------
  // Plan-Based Restrictions (ABAC Layer)
  // -------------------------------------------------------------------------

  const currentPlanLevel = getPlanLevel(planTier);

  // AI features require professional plan or higher
  if (currentPlanLevel < getPlanLevel('professional')) {
    cannot('use', 'AI');
  }

  // Branch management requires business plan or higher
  if (currentPlanLevel < getPlanLevel('business')) {
    cannot('manage', 'Branch');
    cannot('create', 'Branch');
  }

  // API access restrictions (for external API usage)
  if (currentPlanLevel < getPlanLevel('business')) {
    cannot('access', 'all');
  }

  // Analytics export requires starter plan or higher
  if (currentPlanLevel < getPlanLevel('starter')) {
    cannot('export', 'Analytics');
  }

  return build();
}

// -----------------------------------------------------------------------------
// Middleware Functions
// -----------------------------------------------------------------------------

/**
 * Permission middleware that builds CASL ability for the authenticated user.
 * Must be used after authMiddleware and tenantMiddleware.
 *
 * This middleware:
 * 1. Gets user and organization from previous middleware
 * 2. Determines plan tier from organization
 * 3. Builds CASL ability
 * 4. Attaches ability to request
 *
 * @throws AppException.unauthorized() when user is not authenticated
 *
 * @example
 * ```typescript
 * import { authMiddleware } from '@/core/middleware/auth.middleware';
 * import { tenantMiddleware } from '@/core/middleware/tenant.middleware';
 * import { permissionMiddleware, PermissionRequest } from '@/core/middleware/permission.middleware';
 *
 * router.get(
 *   '/menus',
 *   authMiddleware,
 *   tenantMiddleware,
 *   permissionMiddleware,
 *   async (req, res) => {
 *     const { ability } = req as PermissionRequest;
 *     if (ability.can('create', 'Menu')) {
 *       // Show create button
 *     }
 *   }
 * );
 * ```
 */
export const permissionMiddleware: RequestHandler = (
  req: Request,
  _res: Response,
  next: NextFunction
): void => {
  try {
    const authReq = req as TenantRequest;

    // Ensure user is authenticated
    if (!authReq.user) {
      throw AppException.unauthorized('Authentication required for permission check');
    }

    // Get organization and plan info
    const organization = authReq.organization;
    let planTier: PlanTier | null = null;

    // Determine plan tier from organization settings or subscription
    // In a real implementation, this would query the subscription
    if (organization?.settings) {
      planTier = (organization.settings as Record<string, unknown>).planTier as PlanTier | null;
    }

    // If no plan set, default to free tier
    if (!planTier) {
      planTier = 'free';
    }

    // Build CASL ability
    const ability = defineAbilitiesFor(authReq.user, organization, planTier);

    // Attach ability to request
    (req as PermissionRequest).ability = ability;

    next();
  } catch (error) {
    next(error);
  }
};

/**
 * Creates a middleware that requires a specific permission.
 * Must be used after permissionMiddleware.
 *
 * @param action - The action to check (e.g., 'create', 'read', 'update', 'delete')
 * @param subject - The subject/resource type (e.g., 'Menu', 'Order')
 * @param field - Optional field to check permission for
 * @returns Express middleware function
 * @throws AppException.forbidden() when user lacks the required permission
 *
 * @example
 * ```typescript
 * import { requirePermission } from '@/core/middleware/permission.middleware';
 *
 * // Require menu.create permission
 * router.post(
 *   '/menus',
 *   authMiddleware,
 *   tenantMiddleware,
 *   permissionMiddleware,
 *   requirePermission('create', 'Menu'),
 *   createMenuHandler
 * );
 *
 * // Require menu.delete permission
 * router.delete(
 *   '/menus/:id',
 *   authMiddleware,
 *   tenantMiddleware,
 *   permissionMiddleware,
 *   requirePermission('delete', 'Menu'),
 *   deleteMenuHandler
 * );
 * ```
 */
export function requirePermission(
  action: PermissionAction,
  subject: PermissionSubject,
  field?: string
): RequestHandler {
  return (req: Request, _res: Response, next: NextFunction): void => {
    const permReq = req as PermissionRequest;

    if (!permReq.ability) {
      next(AppException.unauthorized('Permission check requires ability context'));
      return;
    }

    const canPerform = field
      ? permReq.ability.can(action, subject, field)
      : permReq.ability.can(action, subject);

    if (!canPerform) {
      next(AppException.forbidden(`${action} ${subject}${field ? `.${field}` : ''}`));
      return;
    }

    next();
  };
}

/**
 * Creates a middleware that requires any of the specified permissions.
 * Must be used after permissionMiddleware.
 *
 * @param permissions - Array of [action, subject] tuples
 * @returns Express middleware function
 * @throws AppException.forbidden() when user lacks all the required permissions
 *
 * @example
 * ```typescript
 * import { requireAnyPermission } from '@/core/middleware/permission.middleware';
 *
 * // Allow if user can create OR update menus
 * router.put(
 *   '/menus/:id',
 *   authMiddleware,
 *   tenantMiddleware,
 *   permissionMiddleware,
 *   requireAnyPermission([
 *     ['create', 'Menu'],
 *     ['update', 'Menu'],
 *   ]),
 *   updateMenuHandler
 * );
 * ```
 */
export function requireAnyPermission(
  permissions: Array<[PermissionAction, PermissionSubject]>
): RequestHandler {
  return (req: Request, _res: Response, next: NextFunction): void => {
    const permReq = req as PermissionRequest;

    if (!permReq.ability) {
      next(AppException.unauthorized('Permission check requires ability context'));
      return;
    }

    const hasAnyPermission = permissions.some(([action, subject]) =>
      permReq.ability.can(action, subject)
    );

    if (!hasAnyPermission) {
      const permList = permissions.map(([a, s]) => `${a} ${s}`).join(' or ');
      next(AppException.forbidden(permList));
      return;
    }

    next();
  };
}

/**
 * Creates a middleware that requires all of the specified permissions.
 * Must be used after permissionMiddleware.
 *
 * @param permissions - Array of [action, subject] tuples
 * @returns Express middleware function
 * @throws AppException.forbidden() when user lacks any of the required permissions
 *
 * @example
 * ```typescript
 * import { requireAllPermissions } from '@/core/middleware/permission.middleware';
 *
 * // Require both menu and product management
 * router.post(
 *   '/menus/:id/products',
 *   authMiddleware,
 *   tenantMiddleware,
 *   permissionMiddleware,
 *   requireAllPermissions([
 *     ['update', 'Menu'],
 *     ['create', 'Product'],
 *   ]),
 *   addProductHandler
 * );
 * ```
 */
export function requireAllPermissions(
  permissions: Array<[PermissionAction, PermissionSubject]>
): RequestHandler {
  return (req: Request, _res: Response, next: NextFunction): void => {
    const permReq = req as PermissionRequest;

    if (!permReq.ability) {
      next(AppException.unauthorized('Permission check requires ability context'));
      return;
    }

    const missingPermissions = permissions.filter(
      ([action, subject]) => !permReq.ability.can(action, subject)
    );

    if (missingPermissions.length > 0) {
      const permList = missingPermissions.map(([a, s]) => `${a} ${s}`).join(', ');
      next(AppException.forbidden(permList));
      return;
    }

    next();
  };
}

/**
 * Creates a middleware that requires a specific plan tier or higher.
 * Must be used after permissionMiddleware.
 *
 * @param minTier - Minimum plan tier required
 * @returns Express middleware function
 * @throws AppException.insufficientPlan() when organization's plan is below required tier
 *
 * @example
 * ```typescript
 * import { requirePlan } from '@/core/middleware/permission.middleware';
 *
 * // Require professional plan for AI features
 * router.post(
 *   '/ai/generate-description',
 *   authMiddleware,
 *   tenantMiddleware,
 *   permissionMiddleware,
 *   requirePlan('professional'),
 *   aiGenerateHandler
 * );
 * ```
 */
export function requirePlan(minTier: PlanTier): RequestHandler {
  return (req: Request, _res: Response, next: NextFunction): void => {
    const permReq = req as PermissionRequest;

    if (!permReq.organization) {
      next(AppException.badRequest('Organization context required for plan check'));
      return;
    }

    // Get current plan tier
    const settings = permReq.organization.settings as Record<string, unknown> | null;
    const currentTier = (settings?.planTier as PlanTier) || 'free';

    const currentLevel = getPlanLevel(currentTier);
    const requiredLevel = getPlanLevel(minTier);

    if (currentLevel < requiredLevel) {
      next(AppException.insufficientPlan('this feature', minTier));
      return;
    }

    next();
  };
}

// -----------------------------------------------------------------------------
// Utility Functions
// -----------------------------------------------------------------------------

/**
 * Gets the CASL ability from request.
 * Throws if ability is not set.
 *
 * @param req - Express request object
 * @returns CASL ability instance
 * @throws AppException.unauthorized() if ability is not set
 *
 * @example
 * ```typescript
 * const ability = getAbility(req);
 * if (ability.can('delete', 'Menu')) {
 *   // Show delete button
 * }
 * ```
 */
export function getAbility(req: Request): AppAbility {
  const permReq = req as PermissionRequest;

  if (!permReq.ability) {
    throw AppException.unauthorized('Permission context required');
  }

  return permReq.ability;
}

/**
 * Gets the CASL ability from request, or undefined if not set.
 *
 * @param req - Express request object
 * @returns CASL ability instance or undefined
 *
 * @example
 * ```typescript
 * const ability = getAbilityOptional(req);
 * if (ability?.can('delete', 'Menu')) {
 *   // Show delete button
 * }
 * ```
 */
export function getAbilityOptional(req: Request): AppAbility | undefined {
  return (req as OptionalPermissionRequest).ability;
}

/**
 * Checks if the request user can perform an action on a subject.
 *
 * @param req - Express request object
 * @param action - The action to check
 * @param subject - The subject/resource type
 * @returns True if user has the permission
 *
 * @example
 * ```typescript
 * if (canPerform(req, 'create', 'Menu')) {
 *   // User can create menus
 * }
 * ```
 */
export function canPerform(
  req: Request,
  action: PermissionAction,
  subject: PermissionSubject
): boolean {
  const ability = getAbilityOptional(req);
  return ability ? ability.can(action, subject) : false;
}

/**
 * Checks if the request user cannot perform an action on a subject.
 *
 * @param req - Express request object
 * @param action - The action to check
 * @param subject - The subject/resource type
 * @returns True if user lacks the permission
 *
 * @example
 * ```typescript
 * if (cannotPerform(req, 'delete', 'Menu')) {
 *   // Hide delete button
 * }
 * ```
 */
export function cannotPerform(
  req: Request,
  action: PermissionAction,
  subject: PermissionSubject
): boolean {
  const ability = getAbilityOptional(req);
  return ability ? ability.cannot(action, subject) : true;
}

/**
 * Asserts that the user can perform an action, throwing if not.
 *
 * @param req - Express request object
 * @param action - The action to check
 * @param subject - The subject/resource type
 * @throws AppException.forbidden() if user lacks the permission
 *
 * @example
 * ```typescript
 * // In a service method
 * assertCan(req, 'delete', 'Menu');
 * await this.menuRepository.delete(menuId);
 * ```
 */
export function assertCan(
  req: Request,
  action: PermissionAction,
  subject: PermissionSubject
): void {
  if (cannotPerform(req, action, subject)) {
    throw AppException.forbidden(`${action} ${subject}`);
  }
}

/**
 * Filters an array of items to only those the user can access.
 * Useful for filtering query results based on permissions.
 *
 * @param req - Express request object
 * @param items - Array of items to filter
 * @param action - The action to check
 * @param subject - The subject/resource type
 * @param getConditions - Function to extract conditions from each item
 * @returns Filtered array of permitted items
 *
 * @example
 * ```typescript
 * const allMenus = await menuRepository.findAll(orgId);
 * const accessibleMenus = filterByPermission(
 *   req,
 *   allMenus,
 *   'read',
 *   'Menu',
 *   (menu) => ({ organizationId: menu.organizationId })
 * );
 * ```
 */
export function filterByPermission<T>(
  req: Request,
  items: T[],
  action: PermissionAction,
  subject: PermissionSubject,
  getConditions: (item: T) => Record<string, unknown>
): T[] {
  const ability = getAbilityOptional(req);
  if (!ability) {
    return [];
  }

  return items.filter((item) => {
    const conditions = getConditions(item);
    return ability.can(action, subject);
  });
}

/**
 * Packs permissions into an array of permission strings.
 * Useful for sending permissions to frontend.
 *
 * @param ability - CASL ability instance
 * @returns Array of permission strings (e.g., ['menu.create', 'menu.update'])
 *
 * @example
 * ```typescript
 * const ability = getAbility(req);
 * const permissions = packPermissions(ability);
 * res.json({ permissions }); // ['menu.create', 'menu.read', 'menu.update']
 * ```
 */
export function packPermissions(ability: AppAbility): string[] {
  const permissions: string[] = [];

  const subjects: PermissionSubject[] = [
    'Organization',
    'Branch',
    'User',
    'Role',
    'Menu',
    'Category',
    'Product',
    'Order',
    'Table',
    'QRCode',
    'Media',
    'Notification',
    'Subscription',
    'Analytics',
    'AI',
    'Module',
    'Settings',
    'AuditLog',
  ];

  const actions: PermissionAction[] = [
    'create',
    'read',
    'update',
    'delete',
    'publish',
    'view',
    'export',
    'import',
    'use',
    'access',
  ];

  for (const subject of subjects) {
    for (const action of actions) {
      if (ability.can(action, subject)) {
        permissions.push(`${subject.toLowerCase()}.${action}`);
      }
    }
    // Check for manage (full control)
    if (ability.can('manage', subject)) {
      permissions.push(`${subject.toLowerCase()}.manage`);
    }
  }

  // Remove duplicates and sort
  return [...new Set(permissions)].sort();
}
